//go:build ignore

// gen_iouring.go extracts io_uring constants from kernel headers.
//
// Usage:
//
//	go generate ./ublk
//
// Or manually:
//
//	go run internal/gen/gen_iouring.go
//
// This requires liburing-dev (or linux headers) to be installed:
//
//	sudo apt-get install liburing-dev  # Debian/Ubuntu
//	sudo dnf install liburing-devel    # Fedora
//
// The generated file is committed to version control so users don't need
// CGO or liburing to build the package.
package main

/*
#include <linux/io_uring.h>
*/
import "C"

import (
	"fmt"
	"os"
	"path/filepath"
	"runtime"
	"time"
)

func main() {
	// Find the output path relative to this generator
	_, thisFile, _, _ := runtime.Caller(0)
	genDir := filepath.Dir(thisFile)
	outputPath := filepath.Join(genDir, "..", "..", "ublk", "iouring_linux.go")

	content := fmt.Sprintf(`// Code generated by go generate; DO NOT EDIT.
// Generated on %s for %s/%s.
//
// Source: linux/io_uring.h (kernel headers)
//
// To regenerate (requires liburing-dev):
//   make generate

//go:build linux

package ublk

// io_uring operation codes from linux/io_uring.h.
const (
	IORING_OP_READ_FIXED  = %d
	IORING_OP_WRITE_FIXED = %d
	IORING_OP_URING_CMD   = %d
)

// io_uring setup flags from linux/io_uring.h.
const (
	IORING_SETUP_IOPOLL        = %d
	IORING_SETUP_SQPOLL        = %d
	IORING_SETUP_SQ_AFF        = %d
	IORING_SETUP_COOP_TASKRUN  = %d
	IORING_SETUP_SQE128        = %d
	IORING_SETUP_SINGLE_ISSUER = %d
	IORING_SETUP_DEFER_TASKRUN = %d
)

// io_uring enter flags from linux/io_uring.h.
const (
	IORING_ENTER_GETEVENTS = %d
)

// SQE flags from linux/io_uring.h.
const (
	IOSQE_FIXED_FILE = %d
)

// Mmap offsets from linux/io_uring.h.
const (
	IORING_OFF_SQ_RING = %#x
	IORING_OFF_CQ_RING = %#x
	IORING_OFF_SQES    = %#x
)
`,
		time.Now().UTC().Format(time.RFC3339),
		runtime.GOOS, runtime.GOARCH,
		// IORING_OP_*
		C.IORING_OP_READ_FIXED,
		C.IORING_OP_WRITE_FIXED,
		C.IORING_OP_URING_CMD,
		// IORING_SETUP_*
		C.IORING_SETUP_IOPOLL,
		C.IORING_SETUP_SQPOLL,
		C.IORING_SETUP_SQ_AFF,
		C.IORING_SETUP_COOP_TASKRUN,
		C.IORING_SETUP_SQE128,
		C.IORING_SETUP_SINGLE_ISSUER,
		C.IORING_SETUP_DEFER_TASKRUN,
		// IORING_ENTER_*
		C.IORING_ENTER_GETEVENTS,
		// IOSQE_*
		C.IOSQE_FIXED_FILE,
		// IORING_OFF_*
		C.IORING_OFF_SQ_RING,
		C.IORING_OFF_CQ_RING,
		C.IORING_OFF_SQES,
	)

	if err := os.WriteFile(outputPath, []byte(content), 0o644); err != nil {
		fmt.Fprintf(os.Stderr, "error writing %s: %v\n", outputPath, err)
		os.Exit(1)
	}
	fmt.Printf("Generated %s\n", outputPath)
}
